import{_ as a,c as t,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse(`{"title":"Multicanal et Plateformes | Tutoriel Clawdbot","description":"Apprenez à configurer et utiliser le système multicanal de Clawdbot, incluant WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS et les plateformes Android.","frontmatter":{"title":"Multicanal et Plateformes | Tutoriel Clawdbot","sidebarTitle":"Intégration d'outils de chat courants","subtitle":"Multicanal et Plateformes","description":"Apprenez à configurer et utiliser le système multicanal de Clawdbot, incluant WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS et les plateformes Android.","tags":["channels","platforms","integration"],"order":60},"headers":[],"relativePath":"fr/moltbot/moltbot/platforms/index.md","filePath":"fr/moltbot/moltbot/platforms/index.md"}`),r={name:"fr/moltbot/moltbot/platforms/index.md"};function n(o,e,l,u,d,c){return s(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="multicanal-et-plateformes" tabindex="-1">Multicanal et Plateformes <a class="header-anchor" href="#multicanal-et-plateformes" aria-label="Permalink to &quot;Multicanal et Plateformes&quot;">​</a></h1><p>Clawdbot prend en charge plusieurs canaux de communication et plateformes via le plan de contrôle unifié de la Gateway, vous permettant d&#39;interagir avec votre assistant AI sur des interfaces familières.</p><h2 id="vue-d-ensemble-du-chapitre" tabindex="-1">Vue d&#39;ensemble du chapitre <a class="header-anchor" href="#vue-d-ensemble-du-chapitre" aria-label="Permalink to &quot;Vue d&#39;ensemble du chapitre&quot;">​</a></h2><p>Ce chapitre présente tous les canaux de communication et plateformes pris en charge par Clawdbot, incluant les applications de messagerie instantanée (WhatsApp, Telegram, Slack, Discord, etc.), les nœuds mobiles (iOS, Android) et les applications de bureau (macOS). Apprenez à configurer ces canaux pour intégrer de manière transparente l&#39;assistant AI dans votre flux de travail quotidien.</p><h2 id="navigation-des-sous-pages" tabindex="-1">Navigation des sous-pages <a class="header-anchor" href="#navigation-des-sous-pages" aria-label="Permalink to &quot;Navigation des sous-pages&quot;">​</a></h2><h3 id="vue-d-ensemble-des-canaux" tabindex="-1">Vue d&#39;ensemble des canaux <a class="header-anchor" href="#vue-d-ensemble-des-canaux" aria-label="Permalink to &quot;Vue d&#39;ensemble des canaux&quot;">​</a></h3><ul><li><strong><a href="./channels-overview/">Vue d&#39;ensemble du système multicanal</a></strong> - Découvrez tous les canaux de communication pris en charge par Clawdbot et leurs caractéristiques, et maîtrisez les concepts de base de configuration des canaux.</li></ul><h3 id="canaux-de-messagerie-instantanee" tabindex="-1">Canaux de messagerie instantanée <a class="header-anchor" href="#canaux-de-messagerie-instantanee" aria-label="Permalink to &quot;Canaux de messagerie instantanée&quot;">​</a></h3><ul><li><strong><a href="./whatsapp/">WhatsApp</a></strong> - Configurer et utiliser le canal WhatsApp (basé sur Baileys), prenant en charge la liaison de périphérique et la gestion de groupes.</li><li><strong><a href="./telegram/">Telegram</a></strong> - Configurer et utiliser le canal Telegram (basé sur grammY Bot API), configurer le Bot Token et le Webhook.</li><li><strong><a href="./slack/">Slack</a></strong> - Configurer et utiliser le canal Slack (basé sur Bolt), intégré à votre espace de travail.</li><li><strong><a href="./discord/">Discord</a></strong> - Configurer et utiliser le canal Discord (basé sur discord.js), prenant en charge les serveurs et les salons.</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Configurer et utiliser le canal Google Chat, intégré avec Google Workspace.</li><li><strong><a href="./signal/">Signal</a></strong> - Configurer et utiliser le canal Signal (basé sur signal-cli), pour une communication privée.</li><li><strong><a href="./imessage/">iMessage</a></strong> - Configurer et utiliser le canal iMessage (exclusif à macOS), intégré à l&#39;application Messages de macOS.</li><li><strong><a href="./line/">LINE</a></strong> - Configurer et utiliser le canal LINE (Messaging API), pour interagir avec les utilisateurs LINE.</li></ul><h3 id="web-et-applications-natives" tabindex="-1">Web et applications natives <a class="header-anchor" href="#web-et-applications-natives" aria-label="Permalink to &quot;Web et applications natives&quot;">​</a></h3><ul><li><strong><a href="./webchat/">Interface WebChat</a></strong> - Utiliser l&#39;interface WebChat intégrée pour interagir avec l&#39;assistant AI, sans configuration de canal externe requise.</li><li><strong><a href="./macos-app/">Application macOS</a></strong> - Découvrez les fonctionnalités de l&#39;application dans la barre de menus macOS, incluant Voice Wake, Talk Mode et le contrôle à distance.</li><li><strong><a href="./ios-node/">Nœud iOS</a></strong> - Configurer le nœud iOS pour exécuter des opérations locales sur l&#39;appareil (Camera, Canvas, Voice Wake).</li><li><strong><a href="./android-node/">Nœud Android</a></strong> - Configurer le nœud Android pour exécuter des opérations locales sur l&#39;appareil (Camera, Canvas).</li></ul><h2 id="suggestions-de-parcours-d-apprentissage" tabindex="-1">Suggestions de parcours d&#39;apprentissage <a class="header-anchor" href="#suggestions-de-parcours-d-apprentissage" aria-label="Permalink to &quot;Suggestions de parcours d&#39;apprentissage&quot;">​</a></h2><p>Selon votre scénario d&#39;utilisation, nous recommandons l&#39;ordre d&#39;apprentissage suivant :</p><h3 id="demarrage-rapide-pour-debutants" tabindex="-1">Démarrage rapide pour débutants <a class="header-anchor" href="#demarrage-rapide-pour-debutants" aria-label="Permalink to &quot;Démarrage rapide pour débutants&quot;">​</a></h3><p>Si vous utilisez Clawdbot pour la première fois, nous vous recommandons d&#39;apprendre dans l&#39;ordre suivant :</p><ol><li><strong><a href="./channels-overview/">Vue d&#39;ensemble du système multicanal</a></strong> - Comprenez d&#39;abord l&#39;architecture globale et les concepts de canaux</li><li><strong><a href="./webchat/">Interface WebChat</a></strong> - La méthode la plus simple, commencez à utiliser sans aucune configuration</li><li><strong>Choisir un canal courant</strong> - Sélectionnez en fonction de vos habitudes quotidiennes : <ul><li>Chat quotidien → <a href="./whatsapp/">WhatsApp</a> ou <a href="./telegram/">Telegram</a></li><li>Collaboration d&#39;équipe → <a href="./slack/">Slack</a> ou <a href="./discord/">Discord</a></li><li>Utilisateurs macOS → <a href="./imessage/">iMessage</a></li></ul></li></ol><h3 id="integration-mobile" tabindex="-1">Intégration mobile <a class="header-anchor" href="#integration-mobile" aria-label="Permalink to &quot;Intégration mobile&quot;">​</a></h3><p>Si vous souhaitez utiliser Clawdbot sur votre téléphone mobile :</p><ol><li><strong><a href="./ios-node/">Nœud iOS</a></strong> - Configurez les fonctionnalités locales sur iPhone/iPad</li><li><strong><a href="./android-node/">Nœud Android</a></strong> - Configurez les fonctionnalités locales sur les appareils Android</li><li><strong><a href="./macos-app/">Application macOS</a></strong> - Utilisez l&#39;application macOS comme centre de contrôle</li></ol><h3 id="deploiement-de-niveau-entreprise" tabindex="-1">Déploiement de niveau entreprise <a class="header-anchor" href="#deploiement-de-niveau-entreprise" aria-label="Permalink to &quot;Déploiement de niveau entreprise&quot;">​</a></h3><p>Si vous devez déployer dans un environnement d&#39;équipe :</p><ol><li><strong><a href="./slack/">Slack</a></strong> - Intégrer avec les espaces de travail de l&#39;équipe</li><li><strong><a href="./discord/">Discord</a></strong> - Établir un serveur communautaire</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Intégrer avec Google Workspace</li></ol><h2 id="conditions-prealables" tabindex="-1">Conditions préalables <a class="header-anchor" href="#conditions-prealables" aria-label="Permalink to &quot;Conditions préalables&quot;">​</a></h2><p>Avant de commencer l&#39;apprentissage de ce chapitre, il est recommandé de terminer :</p><ul><li><strong><a href="./../start/getting-started/">Démarrage rapide</a></strong> - Compléter l&#39;installation et la configuration de base de Clawdbot</li><li><strong><a href="./../start/onboarding-wizard/">Assistant de configuration</a></strong> - Effectuer la configuration de base de la Gateway et des canaux via l&#39;assistant</li></ul><div class="tip custom-block"><p class="custom-block-title">Indication</p><p>Si vous avez déjà terminé l&#39;assistant de configuration, certains canaux peuvent déjà être configurés automatiquement. Vous pouvez sauter les étapes de configuration répétitives et consulter directement les fonctionnalités avancées des canaux spécifiques.</p></div><h2 id="prochaines-etapes" tabindex="-1">Prochaines étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines étapes&quot;">​</a></h2><p>Après avoir terminé l&#39;apprentissage de ce chapitre, vous pouvez continuer à explorer :</p><ul><li><strong><a href="./../advanced/models-auth/">Configuration des modèles AI et de l&#39;authentification</a></strong> - Configurer différents fournisseurs de modèles AI</li><li><strong><a href="./../advanced/session-management/">Gestion de session et multi Agent</a></strong> - Apprendre l&#39;isolation des sessions et la collaboration des sous-agents</li><li><strong><a href="./../advanced/tools-browser/">Système d&#39;outils</a></strong> - Utiliser l&#39;automatisation du navigateur, l&#39;exécution de commandes et d&#39;autres outils</li></ul><h2 id="questions-frequentes" tabindex="-1">Questions fréquentes <a class="header-anchor" href="#questions-frequentes" aria-label="Permalink to &quot;Questions fréquentes&quot;">​</a></h2><details class="details custom-block"><summary>Puis-je utiliser plusieurs canaux simultanément ?</summary><p>Oui ! Clawdbot prend en charge l&#39;activation simultanée de plusieurs canaux. Vous pouvez recevoir et envoyer des messages sur différents canaux, et tous les messages sont traités via la Gateway unifiée.</p></details><details class="details custom-block"><summary>Quel canal est recommandé ?</summary><p>Cela dépend de votre scénario d&#39;utilisation :</p><ul><li><strong>WebChat</strong> - Le plus simple, sans aucune configuration requise</li><li><strong>WhatsApp</strong> - Adapté pour chatter avec vos amis et famille</li><li><strong>Telegram</strong> - API Bot stable, adaptée pour les réponses automatiques</li><li><strong>Slack/Discord</strong> - Adapté pour la collaboration d&#39;équipe</li></ul></details><details class="details custom-block"><summary>La configuration des canaux nécessite-t-elle un paiement ?</summary><p>La plupart des canaux sont gratuits, mais certains peuvent entraîner des coûts :</p><ul><li>WhatsApp Business API - Peut entraîner des frais</li><li>Google Chat - Nécessite un compte Google Workspace</li><li>Autres canaux - Généralement gratuits, il suffit de demander un Bot Token</li></ul></details>',33)])])}const m=a(r,[["render",n]]);export{g as __pageData,m as default};
